INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-a5729396-moex-00184', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '關於遺囑之方式，下列敘述何者正確？', '["自書遺囑者，得以電腦打字為之", "密封遺囑者，應向公證人提出", "代筆遺囑者，應由公證人代筆", "口授遺囑者，因遺囑人生命危急，為保障其立遺囑之權利，該遺囑無須經見證人之見證"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "d2e657417524", "answer_pdf_sha1": "22e4c65c048c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0613", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00185', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '甲駕車在小巷中高速行駛，見到前方不遠處有行人乙。甲明知若繼續高速行駛極有可能會撞到乙，雖無意 致乙於死或重傷，但甲亦不願意減速，想說若乙來不及閃避，真的撞死或撞傷乙也沒關係，最終將乙撞成 重傷。甲之主觀歸責事由應為下列何者？', '["直接故意", "間接故意", "有認識過失", "無認識過失"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "d2e657417524", "answer_pdf_sha1": "22e4c65c048c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0613", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00186', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '下列關於民事責任之敘述，何者錯誤？', '["相較於具體輕過失責任而言，重大過失責任為較輕之責任", "故意或重大過失之責任，可以預先免除", "相較於抽象輕過失責任而言，具體輕過失責任為較輕之責任", "應與處理自己事務為同一注意者，如有重大過失，仍應負責"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "d2e657417524", "answer_pdf_sha1": "22e4c65c048c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0613", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00187', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '結婚不具備實質要件時，關於其效力，下列敘述何者錯誤？', '["當事人未達最低法定結婚年齡者，結婚已逾1年時，縱尚未達最低法定結婚年齡，其法定代理人亦不得 請求撤銷", "監護人與受監護人，於監護關係存續中，未經受監護人父母同意而結婚者，其最近親屬得向法院請求撤 銷；但結婚已逾1年者，不得請求撤銷", "結婚撤銷之效力，不溯及既往", "當事人之一方，因結婚被撤銷而受有損害者，得向他方請求賠償；但他方無過失者，不在此限"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "d2e657417524", "answer_pdf_sha1": "22e4c65c048c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0613", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00188', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '關於占有人，下列敘述何者正確？', '["地上權人為間接占有人", "質權人為自主占有人", "受僱人為占有輔助人", "貸與人為直接占有人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "d2e657417524", "answer_pdf_sha1": "22e4c65c048c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0613", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00189', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '下列有關刑事訴訟法嚴格證明法則之敘述，何者正確？', '["法院認定事實，不必受鑑定報告之拘束", "筆跡是否相符，應送請鑑定，不得由法官自行認定", "法院得單憑告訴人之片面告訴，認定被告之犯罪事實", "沒收的事實及沒收的範圍，均應經嚴格證明"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "d2e657417524", "answer_pdf_sha1": "22e4c65c048c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0613", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00190', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '被告甲為原住民，下列有關其強制辯護之敘述，何者錯誤？', '["甲於偵查程序，未選任辯護人，審判長應指定依法設立之法律扶助機構指派律師", "甲經依通常程序起訴，未選任辯護人，審判長應指定公設辯護人或律師為其辯護", "甲經聲請簡易判決處刑，嗣經法院改依通常程序審理，未選任辯護人，審判長應指定公設辯護人或律師 為其辯護", "甲若已選任辯護人，但於審判期日無正當理由不到，審判長得指定公設辯護人或律師為其辯護"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "d2e657417524", "answer_pdf_sha1": "22e4c65c048c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0613", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00191', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '下列何者符合刑事訴訟法第101條之1的羈押法定事由？', '["被告經通緝到案", "被告曾經犯有偽證罪", "被告犯過失致人於死之重罪有相當理由認為有逃亡之虞", "有事實足認被告有反覆實行竊盜之虞"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "d2e657417524", "answer_pdf_sha1": "22e4c65c048c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0613", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00192', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '在刑事訴訟通常程序中，法院對於證據之合法調查程序，下列敘述何者錯誤？', '["文書可為證據者，須經宣讀或告以要旨", "證人依法應具結而未具結的證言，無證據能力", "法院須以直接、言詞及公開審理原則調查", "證據雖未經合法調查，但若可以發現真實，亦得作為有罪判斷之依據"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "d2e657417524", "answer_pdf_sha1": "22e4c65c048c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0613", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00193', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '有關故意、過失行為之處罰，下列敘述何者錯誤？', '["無論犯罪行為人是基於確定故意或不確定故意而為，均屬故意犯", "刑法上之過失包含有認識之過失與無認識之過失", "加重結果犯是指客觀上發生加重結果，至於行為人能否預見該結果之發生，則非所問", "刑法上的故意包括直接故意與間接故意"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "d2e657417524", "answer_pdf_sha1": "22e4c65c048c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0613", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL)
